const { Manifold, label, setCircularSegments } = api;
setCircularSegments(32);

function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Main body: 28w x 16h x 8d, front at y=-4
const body = box([-14, -4, -8], [14, 4, 8]);

// Speaker rims: colored rings, added first (larger radius = 5)
const rimR = 5.0;
const rimH = 1.5; // 1.5 units deep into body
const spkLRim = Manifold.cylinder(rimH, rimR, rimR, 32).rotate([90, 0, 0]).translate([-9, -4, 0]);
const spkRRim = Manifold.cylinder(rimH, rimR, rimR, 32).rotate([90, 0, 0]).translate([9, -4, 0]);

// Speaker cones: dark inner disc (smaller), protrudes more
const coneR = 3.5;
const coneH = 2.0; // protrudes 2 units into body
const spkLCone = Manifold.cylinder(coneH, coneR, coneR, 32).rotate([90, 0, 0]).translate([-9, -4, 0]);
const spkRCone = Manifold.cylinder(coneH, coneR, coneR, 32).rotate([90, 0, 0]).translate([9, -4, 0]);

// Center cassette deck
const deck = box([-3.5, -4.1, -2.5], [3.5, -2.5, 2.5]);

// Control buttons
const bY0 = -4.1;
const bY1 = -3.2;
const btn1 = box([-3.0, bY0, -5.0], [-2.2, bY1, -4.4]);
const btn2 = box([-1.8, bY0, -5.0], [-1.0, bY1, -4.4]);
const btn3 = box([-0.4, bY0, -5.0], [0.4, bY1, -4.4]);
const btn4 = box([0.8, bY0, -5.0], [1.6, bY1, -4.4]);
const btn5 = box([2.0, bY0, -5.0], [2.8, bY1, -4.4]);

// Handle on top: arch
const handlePostL = box([-4.5, -0.6, 8], [-3.5, 0.6, 11]);
const handlePostR = box([3.5, -0.6, 8], [4.5, 0.6, 11]);
const handleBar = box([-3.5, -0.5, 10.3], [3.5, 0.5, 11]);

// Build union step by step using labels:
// 1. Body (unlabeled base)
// 2. Add labeled rims
// 3. Add labeled cones (on top of rims — the NEW part of cones gets labeled)
// 4. Add rest

const bodyBase = label(body, 'body');
const rimsLabeled = label(spkLRim.add(spkRRim), 'rims');
const conesLabeled = label(spkLCone.add(spkRCone), 'speakers');
const deckLabeled = label(deck, 'deck');
const btnsLabeled = label(btn1.add(btn2).add(btn3).add(btn4).add(btn5), 'buttons');
const handleLabeled = label(handlePostL.add(handlePostR).add(handleBar), 'handle');

return bodyBase
  .add(rimsLabeled)
  .add(conesLabeled)
  .add(deckLabeled)
  .add(btnsLabeled)
  .add(handleLabeled);
